Tablesorter v2.31.0 is now available, and on npm.

All widgets, parsers & extras javascript files should now work as follows:

```js
var $ = require("jquery");

var folder = "./node_modules/tablesorter/dist/";
require("tablesorter"); // tablesorter function is returned, but it is attached to jQuery
require(folder + "js/parsers/parser-metric.min.js"); // jQuery is returned, not the parser
require(folder + "js/widgets/widget-math.min.js"); // jQuery is returned, not the widget

// tablesorterPager is returned, but you still initialize it from jQuery
var tablesorterPager = require(folder + "js/extras/jquery.tablesorter.pager.min.js"); 

$(".sortable")
  .tablesorter({
    headers: {
      3: { sorter: "metric" }
    },
    widgets: ["zebra", "math"]
  })
  .tablesorterPager({
    container: $(".pager")
  });

```

